import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: URL {
        switch self {
        case .development:
            return URL(string: "https://api.dev.example.com")!
        case .staging:
            return URL(string: "https://api.stg.example.com")!
        case .production:
            return URL(string: "https://api.example.com")!
        }
    }
}

enum APIError: Error {
    case invalidURL
    case networkFailure
    case dataDecodingFailure
}

class NetworkManager {
    
    static let shared = NetworkManager()
    
    private init() {}
    
    func fetchData(urlString: String, completion: @escaping (Result<Data, APIError>) -> Void) {
        guard let url = URL(string: urlString) else {
            completion(.failure(.invalidURL))
            return
        }
        
        let task = URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(.networkFailure))
                return
            }
            
            guard let data = data else {
                completion(.failure(.dataDecodingFailure))
                return
            }
            
            completion(.success(data))
        }
        
        task.resume()
    }
    
    func postData(urlString: String, parameters: [String: Any], completion: @escaping (Result<Data, APIError>) -> Void) {
        guard let url = URL(string: urlString) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: parameters, options: [])
        } catch {
            completion(.failure(.dataDecodingFailure))
            return
        }
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.networkFailure))
                return
            }
            
            guard let data = data else {
                completion(.failure(.dataDecodingFailure))
                return
            }
            
            completion(.success(data))
        }
        
        task.resume()
    }
}